-- Create bl2 table
CREATE TABLE IF NOT EXISTS bl2 (
  id              bigserial PRIMARY KEY,
  line_id         text NOT NULL UNIQUE,
  line_name       text,
  partner         text,
  region          text CHECK (region IN ('N','S','W')),
  buses           integer DEFAULT 1,
  bus_type        text,
  gst_slab        smallint CHECK (gst_slab IN (5, 18)),
  ow_km           numeric,
  rt              numeric,
  min_g           numeric,
  pc5             numeric,
  pc_gst          numeric,
  delta           numeric,
  monthly_lakhs   numeric,
  -- Supply columns
  oem             text,
  body_builder    text,
  bus_age_years   numeric,
  manufacture_year integer,
  seat_config     text,
  -- Renegotiation tracking
  original_ming   numeric,
  last_renegotiation_date date,
  last_ming_change numeric,
  created_at      timestamptz DEFAULT now()
);

CREATE INDEX IF NOT EXISTS idx_bl2_line ON bl2 (line_id);
CREATE INDEX IF NOT EXISTS idx_bl2_partner ON bl2 (partner);
CREATE INDEX IF NOT EXISTS idx_bl2_region ON bl2 (region);


-- Seed 125 lines from baseline.ts
ON CONFLICT (line_id) DO NOTHING;

